    id bigint NOT NULL GENERATED ALWAYS AS IDENTITY ( INCREMENT 1 START 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1 ),
    project_id bigint NOT NULL,
    version_no integer NOT NULL,
    version_notes text COLLATE pg_catalog."default",
    snapshot_data jsonb NOT NULL,
    created_by bigint NOT NULL,
    created_at timestamp with time zone NOT NULL DEFAULT now(),
    CONSTRAINT pk_project_versions PRIMARY KEY (id),
    CONSTRAINT uq_project_version UNIQUE (project_id, version_no)
);

CREATE TABLE IF NOT EXISTS core.projects
(
    id bigint NOT NULL GENERATED ALWAYS AS IDENTITY ( INCREMENT 1 START 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1 ),
    institution_id bigint NOT NULL,
    project_code character varying(100) COLLATE pg_catalog."default" NOT NULL,
    title_ar character varying(1000) COLLATE pg_catalog."default" NOT NULL,
    title_en character varying(1000) COLLATE pg_catalog."default",
    abstract_ar text COLLATE pg_catalog."default",
    abstract_en text COLLATE pg_catalog."default",
    objectives text COLLATE pg_catalog."default",
    principal_investigator_id bigint NOT NULL,
    research_category character varying(100) COLLATE pg_catalog."default",
    risk_level character varying(50) COLLATE pg_catalog."default",
    status_code character varying(50) COLLATE pg_catalog."default" NOT NULL DEFAULT 'DRAFT'::character varying,
    start_date date,
    expected_end_date date,
    created_at timestamp with time zone NOT NULL DEFAULT now(),
    updated_at timestamp with time zone,
    CONSTRAINT pk_projects PRIMARY KEY (id),
    CONSTRAINT uq_projects_code UNIQUE (project_code)
);

